import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';

import '../customization/generic_grid_card.dart';
import 'empresa_model.dart';
import 'login_model.dart';
import 'parceiro_model.dart';
import 'setor_model.dart';
import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/customization/generic_grid_card.dart';
import 'package:task_manager_flutter/data/models/empresa_model.dart';
import 'package:task_manager_flutter/data/models/parceiro_model.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';

class ContaBancaria {
  int? id;
  String? banco;
  String? agencia;
  String? numero;
  String? descricao;
  double? saldoAtual;
  Empresa empresa;
  Parceiro? parceiro;
  bool ativo;

  ContaBancaria({
    this.id,
    this.banco,
    this.agencia,
    this.numero,
    this.descricao,
    this.saldoAtual,
    required this.empresa,
    this.parceiro,
    this.ativo = true,
  });

  factory ContaBancaria.fromJson(Map<String, dynamic> json) {
    return ContaBancaria(
      id: json['id'],
      banco: json['banco'],
      agencia: json['agencia'],
      numero: json['numero'],
      descricao: json['descricao'],
      saldoAtual: (json['saldoAtual'] ?? 0).toDouble(),
      empresa: Empresa.fromJson(json['empresa']),
      parceiro:
          json['parceiro'] != null ? Parceiro.fromJson(json['parceiro']) : null,
      ativo: json['ativo'] ?? true,
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'banco': banco,
      'agencia': agencia,
      'numero': numero,
      'descricao': descricao,
      'saldoAtual': saldoAtual,
      'empresa': empresa.toJson(),
      if (parceiro != null) 'parceiro': parceiro!.toJson(),
      'ativo': ativo,
    };
  }

  // 🔄 Métodos auxiliares para dropdowns
  static Future<List<Map<String, dynamic>>> loadEmpresas() async {
    final NetworkResponse response =
        await NetworkCaller().getRequest(ApiLinks.allEmpresas);
    if (response.isSuccess && response.body != null) {
      final List<dynamic> data = response.body!['data']['dados'] ?? [];
      return data
          .map((item) =>
              {'value': item['id'], 'label': item['nomeFantasia'].toString()})
          .toList();
    }
    return [];
  }

  static Future<List<Map<String, dynamic>>> loadParceiros() async {
    final NetworkResponse response =
        await NetworkCaller().getRequest(ApiLinks.allParceiros);
    if (response.isSuccess && response.body != null) {
      final List<dynamic> data = response.body!['data']['dados'] ?? [];
      return data
          .map(
              (item) => {'value': item['id'], 'label': item['nome'].toString()})
          .toList();
    }
    return [];
  }

  // ⚙️ Configuração do grid e formulários
  static List<FieldConfig> fieldConfigs = [
    const FieldConfig(
      label: "Banco",
      fieldName: "banco",
      icon: Icons.account_balance,
      isInForm: true,
      isFilterable: true,
      isVisibleByDefault: true,
      isFixed: true,
      fieldType: FieldType.text,
    ),
    const FieldConfig(
      label: "Agência",
      fieldName: "agencia",
      icon: Icons.business,
      isInForm: true,
      isVisibleByDefault: true,
      isFixed: false,
      fieldType: FieldType.text,
    ),
    const FieldConfig(
      label: "Número",
      fieldName: "numero",
      icon: Icons.numbers,
      isInForm: true,
      isVisibleByDefault: true,
      isFixed: false,
      fieldType: FieldType.text,
    ),
    const FieldConfig(
      label: "Descrição",
      fieldName: "descricao",
      icon: Icons.description,
      isInForm: true,
      isVisibleByDefault: true,
      isFixed: false,
      fieldType: FieldType.text,
    ),
    FieldConfig(
      label: "Empresa",
      fieldName: "empresa.id",
      displayFieldName: "empresa.nomeFantasia",
      icon: Icons.apartment,
      isInForm: true,
      isFilterable: true,
      fieldType: FieldType.dropdown,
      dropdownFutureBuilder: () async => await loadEmpresas(),
      dropdownValueField: 'value',
      dropdownDisplayField: 'label',
      isRequired: true,
    ),
    FieldConfig(
      label: "Parceiro",
      fieldName: "parceiro.id",
      displayFieldName: "parceiro.nome",
      icon: Icons.people,
      isInForm: true,
      isFilterable: true,
      fieldType: FieldType.dropdown,
      dropdownFutureBuilder: () async => await loadParceiros(),
      dropdownValueField: 'value',
      dropdownDisplayField: 'label',
    ),
    const FieldConfig(
      label: "Saldo Atual",
      fieldName: "saldoAtual",
      icon: Icons.monetization_on,
      isInForm: false,
      isVisibleByDefault: true,
      isFixed: false,
      fieldType: FieldType.decimal,
    ),
    const FieldConfig(
      label: "Ativo",
      fieldName: "ativo",
      icon: Icons.toggle_on,
      isInForm: true,
      isVisibleByDefault: true,
      isFixed: false,
      fieldType: FieldType.bool,
    ),
  ];
}
